function init(cfg) {
  _cfg = validate(cfg || {});
}

function recordMetric(name, value) {
  const entry = { name, value };
  _records.push(entry);
  emit(EVENTS.METRIC_RECORDED, entry);
  return STRINGS.METRIC_RECORDED
    .replace('{name}', name)
    .replace('{value}', value);
}

function getRecords() {
