const { EVENTS, emit } = require('../bus.js');
const { CONFIG_SCHEMA, validate } = require('../config.js');
const { STRINGS } = require('../strings.js');

// Extend CONFIG_SCHEMA with notifications-specific keys.
CONFIG_SCHEMA['notifications.maxQueue'] = { type: 'number', default: 50 };

const _queues = {};
let _cfg = validate({});

function init(cfg) {
  _cfg = validate(cfg || {});
}

function send(user, message) {
  if (!_queues[user]) {
    _queues[user] = [];
  }
  const queue = _queues[user];
  queue.push(message);
  if (queue.length > _cfg['notifications.maxQueue']) {
    queue.shift();
  }
  emit(EVENTS.MESSAGE_QUEUED, { user, message });
  return STRINGS.MESSAGE_QUEUED
    .replace('{user}', user)
    .replace('{message}', message);
}

function list(user) {
  return (_queues[user] || []).slice();
}

function clear(user) {
  delete _queues[user];
}

module.exports = { init, send, list, clear };

